// --- NetworkModule.kt ---
package com.example.network

import com.example.network.api.UserApiService
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var retrofit: Retrofit? = null
    private var tokenProvider: TokenProvider = InMemoryTokenProvider()
    private var currentEnvironment: Environment = Environment.current

    fun initialize(
        environment: Environment = Environment.DEV,
        provider: TokenProvider = InMemoryTokenProvider()
    ) {
        currentEnvironment = environment
        Environment.current = environment
        tokenProvider = provider
        retrofit = null // Force rebuild
    }

    fun getTokenProvider(): TokenProvider = tokenProvider

    private fun buildOkHttpClient(): OkHttpClient {
        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = when (currentEnvironment) {
                Environment.DEV -> HttpLoggingInterceptor.Level.BODY
                Environment.STAGING -> HttpLoggingInterceptor.Level.BASIC
                Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
            }
        }

        return OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor(tokenProvider))
            .addInterceptor(loggingInterceptor)
            .authenticator(AuthAuthenticator(tokenProvider))
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .build()
    }

    private fun getRetrofit(): Retrofit {
        if (retrofit == null || Environment.current != currentEnvironment) {
            currentEnvironment = Environment.current
            val gson = GsonBuilder()
                .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
                .setLenient()
                .create()

            retrofit = Retrofit.Builder()
                .baseUrl(currentEnvironment.baseUrl)
                .client(buildOkHttpClient())
                .addConverterFactory(GsonConverterFactory.create(gson))
                .build()
        }
        return retrofit!!
    }

    val userApiService: UserApiService
        get() = getRetrofit().create(UserApiService::class.java)
}

// --- SafeApiCall.kt ---
package com.example.network

import retrofit2.Response

suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): ApiResult<T> {
    return try {
        val response = apiCall()
        if (response.isSuccessful) {
            val body = response.body()
            if (body != null) {
                ApiResult.Success(body)
            } else {
                ApiResult.Error(response.code(), "Empty response body")
            }
        } else {
            val errorBody = response.errorBody()?.string() ?: "Unknown error"
            ApiResult.Error(response.code(), errorBody)
        }
    } catch (e: java.io.IOException) {
        ApiResult.Exception(e)
    } catch (e: kotlin.coroutines.cancellation.CancellationException) {
        throw e
    } catch (e: Exception) {
        ApiResult.Exception(e)
    }
}

