// Example ViewModel usage
class UsageExample {

    private val userRepository = UserRepository()

    fun fetchUsers() {
        CoroutineScope(Dispatchers.IO).launch {
            when (val result = userRepository.getUsers(page = 1)) {
                is ApiResult.Success -> {
                    val users = result.data.data
                    println("Fetched ${users.size} users")
                    users.forEach { user ->
                        println("User: ${user.username} (${user.email})")
                    }
                }
                is ApiResult.Error -> {
                    println("API Error: ${result.code} - ${result.message}")
                }
                is ApiResult.Exception -> {
                    println("Network Exception: ${result.throwable.message}")
                }
            }
        }
    }

    fun fetchCurrentUser() {
        CoroutineScope(Dispatchers.IO).launch {
            when (val result = userRepository.getCurrentUser()) {
                is ApiResult.Success -> {
                    val profile = result.data.data
                    println("Current user: ${profile.firstName} ${profile.lastName}")
                }
                is ApiResult.Error -> {
                    println("Error: ${result.code} - ${result.message}")
                }
                is ApiResult.Exception -> {
                    println("Exception: ${result.throwable.message}")
                }
            }
        }
    }

    fun updateProfile(firstName: String, lastName: String) {
        CoroutineScope(Dispatchers.IO).launch {
            val updates = mapOf(
                "first_name" to firstName,
                "last_name" to lastName
            )
            when (val result = userRepository.updateCurrentUser(updates)) {
                is ApiResult.Success -> {
                    println("Profile updated: ${result.data.data.firstName}")
                }
                is ApiResult.Error -> {
                    println("Update failed: ${result.message}")
                }
                is ApiResult.Exception -> {
                    println("Exception: ${result.throwable.message}")
                }
            }
        }
    }
}